import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, Modality, Type } from "@google/genai";

// AI Tech Theme Colors - CUD & MED SAWA Identity
const THEME_BLUE_CUD = '#1E3A8A'; 
const THEME_ORANGE_SAWA = '#F97316'; 

interface ResponseContent {
  titre: string;
  paragraphes: string[];
  motsCles: string[];
  etapeSuivante: string;
  suggestions?: string[];
}

interface Message {
  id: string;
  structuredContent?: ResponseContent;
  rawText?: string;
  sender: 'user' | 'ai';
  timestamp: string;
  file?: {
    name: string;
    type: string;
    url: string;
  };
  suggestions?: string[]; 
}

interface PillarData {
  title: string;
  description: string;
  detail: string;
  roi: string;
  icon: React.ReactNode;
}

// Audio Decoding Utilities
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const cleanJson = (text: string) => {
  let cleaned = text.trim();
  if (cleaned.startsWith('```json')) {
    cleaned = cleaned.replace(/^```json/, '').replace(/```$/, '');
  } else if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```/, '').replace(/```$/, '');
  }
  return cleaned.trim();
};

const HighlightText = ({ text, keywords, isClosing = false }: { text: string, keywords: string[], isClosing?: boolean }) => {
  if (!keywords || keywords.length === 0) return <span>{text}</span>;
  const escapedKeywords = keywords.map(kw => kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
  const regex = new RegExp(`(${escapedKeywords.join('|')})`, 'gi');
  const parts = text.split(regex);

  return (
    <>
      {parts.map((part, i) => {
        const isKeyword = keywords.some(kw => kw.toLowerCase() === part.toLowerCase());
        return isKeyword ? (
          <span key={i} className={`font-bold ${isClosing ? 'text-orange-600' : 'text-blue-900'}`}>
            {part}
          </span>
        ) : (
          <span key={i}>{part}</span>
        );
      })}
    </>
  );
};

const FormatResponse = ({ content }: { content: ResponseContent }) => {
  return (
    <div className="flex flex-col gap-5 text-slate-700 leading-relaxed font-normal">
      {content.titre && (
        <h4 className="text-lg font-bold tracking-tight uppercase border-b border-orange-100 pb-2" style={{ color: THEME_ORANGE_SAWA }}>
          {content.titre}
        </h4>
      )}

      {content.paragraphes.map((para, idx) => (
        <p key={idx} className="animate-fadeIn text-base text-justify">
          <HighlightText text={para} keywords={content.motsCles} />
        </p>
      ))}

      {content.etapeSuivante && (
        <div className="mt-2 p-4 bg-orange-50/50 border-l-4 border-orange-500 rounded-r-xl italic text-sm text-slate-600 shadow-inner">
          <HighlightText text={content.etapeSuivante} keywords={content.motsCles} isClosing={true} />
        </div>
      )}
    </div>
  );
};

const PillarCard: React.FC<{ pillar: PillarData; onClick: (pillar: PillarData) => void }> = ({ pillar, onClick }) => {
  return (
    <div onClick={() => onClick(pillar)} className="group relative bg-white rounded-xl p-5 flex flex-col justify-between cursor-pointer transition-all duration-300 transform hover:shadow-xl border border-slate-100 hover:border-blue-900 overflow-hidden min-h-[140px]">
      <div className="relative z-10">
        <div className="flex justify-between items-center mb-3">
          <div className="text-blue-900 group-hover:text-orange-600 transition-colors">
             {pillar.icon}
          </div>
          <span className="text-[8px] font-black text-white bg-blue-900 px-2 py-0.5 rounded shadow-sm tracking-widest">{pillar.roi}</span>
        </div>
        <h3 className="font-heading font-bold text-sm mb-1 text-blue-950 group-hover:text-orange-600 transition-colors uppercase">{pillar.title}</h3>
        <p className="text-slate-500 text-[10px] leading-tight font-medium line-clamp-2">{pillar.description}</p>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState<string>('');
  const [isRecording, setIsRecording] = useState<boolean>(false);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false); 
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatMessagesRef = useRef<HTMLDivElement>(null);
  const aiRef = useRef<GoogleGenAI | null>(null);
  const chatSessionRef = useRef<any>(null); 
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const currentPlayingSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const pillars: PillarData[] = [
    { 
      title: 'Urbanisme & Titres', 
      description: 'Instruction automatisée des Permis de Bâtir et Certificats.', 
      detail: 'Vérification de conformité IA.', 
      roi: 'PHASE 1',
      icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
    },
    { 
      title: 'Civisme & Guichet', 
      description: 'Information citoyenne de Bonabéri à Edéa via WhatsApp.', 
      detail: 'Assistance actes de naissance.', 
      roi: 'DIRECT',
      icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8h2a2 2 0 012 2v6a2 2 0 01-2 2h-2v4l-4-4H9a1.994 1.994 0 01-1.414-.586m0 0L11 14h4a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2v4l.586-.586z" /></svg>
    },
    { 
      title: 'Fiscalité Locale', 
      description: 'Carte grise fiscale : Akwa, Bonanjo, New Bell.', 
      detail: 'Recouvrement optimisé.', 
      roi: 'REVENUS',
      icon: <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    },
  ];

  const playAudioResponse = useCallback(async (text: string) => {
    const ai = aiRef.current;
    if (!ai) return;

    if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new window.AudioContext({ sampleRate: 24000 });
    }
    const outputAudioContext = outputAudioContextRef.current;
    if (outputAudioContext.state === 'suspended') await outputAudioContext.resume();

    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
        const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
        const source = outputAudioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(outputAudioContext.destination);
        source.addEventListener('ended', () => currentPlayingSourcesRef.current.delete(source));
        source.start(nextStartTimeRef.current);
        nextStartTimeRef.current += audioBuffer.duration;
        currentPlayingSourcesRef.current.add(source);
      }
    } catch (error) { console.warn('TTS error:', error); }
  }, []);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    aiRef.current = ai;
    outputAudioContextRef.current = new window.AudioContext({ sampleRate: 24000 });

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            titre: { type: Type.STRING },
            paragraphes: { type: Type.ARRAY, items: { type: Type.STRING } },
            motsCles: { type: Type.ARRAY, items: { type: Type.STRING } },
            etapeSuivante: { type: Type.STRING },
            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["titre", "paragraphes", "motsCles", "etapeSuivante", "suggestions"]
        },
        systemInstruction: `
          TON IDENTITÉ : Expert Principal MED SAWA. Leader d'opinion Smart City.
          MISSION : Assistance technique stratégique pour le Maire de Douala et la CUD.

          POSTURE : Intellectuellement agressive, technique, souveraine.
          CONTENU OBLIGATOIRE :
          1. URBANISME : Mentionne l'IA pour la vérification automatique des dossiers de Permis de Bâtir à Akwa ou Deido. Réduction drastique des délais.
          2. FISCALITÉ : Parle de la "Carte Grise Fiscale" pour Akwa et Bonanjo afin de capter les milliards perdus.
          3. CITOYENNETÉ : DOULIA est le guichet unique. Mentionne le trajet Bonabéri-Edéa.
          4. MULTIMODALITÉ : Identification des pathologies urbaines (nids-de-poule, occupations illégales) par analyse d'image.

          RÈGLES DE RÉPONSE :
          - AUCUN ASTÉRISQUE (*).
          - FORMAT JSON EXCLUSIF.
          - LANGUE : 100% Français.
          - SOUVERAINETÉ : Rappelle que les données restent au Cameroun via MED SAWA.
        `,
      },
    });

    const initChat = async () => {
      try {
        const result = await chatSessionRef.current.sendMessage({
          message: "Présente ta vision souveraine pour la CUD et propose un diagnostic sur la capture des recettes fiscales à Akwa."
        });
        const parsed = JSON.parse(cleanJson(result.text));
        setMessages([{ 
          id: 'welcome', 
          structuredContent: parsed, 
          sender: 'ai', 
          timestamp: new Date().toLocaleTimeString(), 
          suggestions: parsed.suggestions 
        }]);
        playAudioResponse(`${parsed.titre}. ${parsed.paragraphes[0]}`);
      } catch (e) { console.error("Init error", e); }
    };
    initChat();
  }, [playAudioResponse]);

  const handleSendMessage = useCallback(async (text: string, file?: File | null) => {
    const targetFile = file || selectedFile;
    if (!text.trim() && !targetFile) return;

    if (targetFile) setIsAnalyzing(true);
    const userMsg: Message = { 
      id: `u-${Date.now()}`, 
      rawText: text || (targetFile ? `PIÈCE JOINTE : ${targetFile.name}` : ''), 
      sender: 'user', 
      timestamp: new Date().toLocaleTimeString() 
    };
    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setSelectedFile(null);

    try {
      let result;
      if (targetFile) {
        const part = await fileToGenerativePart(targetFile);
        result = await chatSessionRef.current.sendMessage({ 
          message: { parts: [{ text: text || "Analyse technique de cette pièce urbaine." }, part] } 
        });
      } else {
        result = await chatSessionRef.current.sendMessage({ message: text });
      }

      const parsed = JSON.parse(cleanJson(result.text));
      const aiMsg: Message = { 
        id: `ai-${Date.now()}`, 
        structuredContent: parsed, 
        sender: 'ai', 
        timestamp: new Date().toLocaleTimeString(), 
        suggestions: parsed.suggestions 
      };
      setMessages(prev => [...prev, aiMsg]);
      playAudioResponse(`${parsed.titre}. ${parsed.paragraphes[0]}`);
    } catch (e) {
      console.error(e);
      setMessages(prev => [...prev, { id: 'err', rawText: "Interruption technique. Relance de la session MED SAWA.", sender: 'ai', timestamp: new Date().toLocaleTimeString() }]);
    } finally { setIsAnalyzing(false); }
  }, [playAudioResponse, selectedFile]);

  useEffect(() => { if (chatMessagesRef.current) chatMessagesRef.current.scrollTop = chatMessagesRef.current.scrollHeight; }, [messages]);

  return (
    <div className="h-screen flex flex-col font-sans bg-white overflow-hidden relative">
      <div className="fixed inset-0 z-0 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-blue-100/10 via-white to-orange-100/10"></div>

      {/* HEADER COMPACT */}
      <header className="relative z-30 bg-white/80 backdrop-blur-md border-b border-slate-100 px-6 py-4 flex items-center justify-between shadow-sm flex-none">
        <div className="flex items-center gap-3">
