            <div className="h-8 w-px bg-slate-200 hidden sm:block"></div>
            <div className="hidden sm:flex flex-col">
              <h1 className="text-xs font-black text-blue-900 tracking-tighter uppercase">Assistant DOULIA</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase">Expertise MED SAWA</span>
            </div>
        </div>
        <div className="flex items-center gap-4">
             <div className="flex flex-col items-end">
                 <span className="text-[10px] font-black text-blue-950 uppercase">Session Sécurisée</span>
                 <span className="text-[8px] font-bold text-green-500 animate-pulse uppercase">En ligne | Douala</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-blue-950 flex items-center justify-center text-white font-black text-xs">SA</div>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden relative z-10 p-2 sm:p-4 gap-4">
        {/* SIDEBAR D'EXPERTISE */}
        <aside className="w-[280px] hidden lg:flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-1 h-full flex-none">
          <div className="bg-gradient-to-br from-blue-950 to-blue-900 text-white p-6 rounded-2xl shadow-lg relative overflow-hidden">
            <div className="absolute top-0 right-0 w-24 h-24 bg-orange-500/10 rounded-full -mr-10 -mt-10"></div>
            <h3 className="font-bold text-xs mb-1 flex items-center gap-2 relative z-10 uppercase">
                <span className="w-2 h-2 rounded-full bg-orange-500"></span>
                Souveraineté Numérique
            </h3>
            <p className="text-[10px] opacity-80 leading-snug font-medium">Les données de Douala restent au Cameroun. MED SAWA opère en circuit court.</p>
