          <div className="flex-1 space-y-3">
            {pillars.map((p, idx) => <PillarCard key={idx} pillar={p} onClick={(pill) => handleSendMessage(`Focus : ${pill.title}`)} />)}
          </div>

          <div className="bg-slate-50 border border-slate-100 p-4 rounded-xl">
             <h4 className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-2">Quartiers en monitoring</h4>
             <div className="flex flex-wrap gap-1.5">
