            <h2 className="text-xs font-black text-blue-950 flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-orange-600"></div>
              DOULIA : ANALYSE STRATÉGIQUE CUD
            </h2>
            <button className="text-[8px] font-black text-slate-400 hover:text-orange-600 uppercase transition-colors">Réinitialiser Audit</button>
          </div>

          {/* Zone de messages - Prend tout l'espace central */}
          <div ref={chatMessagesRef} className="flex-1 overflow-y-auto p-4 sm:p-8 custom-scrollbar scroll-smooth space-y-8">
            {messages.map((msg) => (
