                </button>

                <input 
                  type="text" 
                  value={inputMessage} 
                  onChange={(e) => setInputMessage(e.target.value)} 
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage(inputMessage)}
                  placeholder="SAISIR UNE REQUÊTE TECHNIQUE (FONCIER, FISCALITÉ, URBANISME)..." 
                  className="w-full h-12 pl-12 pr-12 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-900/5 focus:border-blue-900 outline-none text-sm bg-slate-50 transition-all font-medium text-slate-800 placeholder:text-slate-300 placeholder:font-black placeholder:text-[9px]"
                />

                {/* Bouton Micro Intégré */}
                <button 
                  onClick={() => setIsRecording(!isRecording)}
                  className={`absolute right-3 w-8 h-8 rounded-lg flex items-center justify-center transition-all ${isRecording ? 'bg-orange-600 text-white animate-pulse' : 'text-slate-400 hover:text-blue-900'}`}
                  title="Dictée vocale technique"
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 2.99-1.34 2.99-3L15 5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3zm5.2-3c0 3.53-2.9 6.43-6.4 6.43S4.8 14.53 4.8 11H3c0 4.28 3.3 7.85 7.6 8.45V22h3.4v-2.55c4.3-.6 7.6-4.17 7.6-8.45h-1.8z"/></svg>
                </button>
              </div>

              <button 
                onClick={() => handleSendMessage(inputMessage)} 
                disabled={isAnalyzing}
                className={`h-12 px-6 rounded-xl text-white font-black text-[10px] uppercase tracking-widest shadow-lg transition-all flex items-center gap-2 ${isAnalyzing ? 'bg-slate-400 animate-pulse cursor-not-allowed' : 'bg-blue-950 hover:bg-orange-600 active:scale-95'}`}
