  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false); 
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatMessagesRef = useRef<HTMLDivElement>(null);
  const aiRef = useRef<GoogleGenAI | null>(null);
  const chatSessionRef = useRef<any>(null); 
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const currentPlayingSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const pillars: PillarData[] = [
    { 
      title: 'Audit Territorial', 
      description: 'Phase 1 : Cartographie des pathologies urbaines et gisements fiscaux.', 
      detail: 'Diagnostic préalable IA.', 
