            <div className="h-8 w-px bg-slate-200 hidden sm:block"></div>
            <div className="hidden sm:flex flex-col">
              <h1 className="text-xs font-black text-blue-900 tracking-tighter uppercase">ASSISTANT MED SAWA</h1>
              <span className="text-[9px] font-bold text-orange-500 uppercase">Expertise DOULIA</span>
            </div>
