// Audio Decoding Utilities
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const cleanJson = (text: string) => {
  let cleaned = text.trim();
  if (cleaned.startsWith('```json')) {
    cleaned = cleaned.replace(/^```json/, '').replace(/```$/, '');
  } else if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```/, '').replace(/```$/, '');
  }
  return cleaned.trim();
};

const HighlightText = ({ text, keywords, isClosing = false }: { text: string, keywords: string[], isClosing?: boolean }) => {
  if (!keywords || keywords.length === 0) return <span>{text}</span>;
  const escapedKeywords = keywords.map(kw => kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
  const regex = new RegExp(`(${escapedKeywords.join('|')})`, 'gi');
  const parts = text.split(regex);

  return (
    <>
      {parts.map((part, i) => {
        const isKeyword = keywords.some(kw => kw.toLowerCase() === part.toLowerCase());
        return isKeyword ? (
          <span key={i} className="font-bold" style={{ color: isClosing ? THEME_ORANGE_SAWA : THEME_BLUE_CUD }}>
            {part}
          </span>
        ) : (
          <span key={i}>{part}</span>
        );
      })}
    </>
  );
};

const FormatResponse = ({ content }: { content: ResponseContent }) => {
  const renderParagraph = (para: string, idx: number) => {
    const trimmed = para.trim();
    // Détection Bullet points
    const bulletMatch = trimmed.match(/^([•\-\*])\s*(.*)/);
    // Détection Listes numérotées
    const numberMatch = trimmed.match(/^(\d+)[\.\)]\s*(.*)/);

    if (bulletMatch) {
      return (
        <div key={idx} className="animate-fadeIn text-[15px] pl-7 relative leading-relaxed mb-3 text-slate-700">
          <span className="absolute left-1 top-0 text-orange-500 font-black text-lg leading-none">•</span>
          <HighlightText text={bulletMatch[2]} keywords={content.motsCles} />
        </div>
      );
    }

    if (numberMatch) {
      return (
        <div key={idx} className="animate-fadeIn text-[15px] pl-9 relative leading-relaxed mb-4 text-slate-700">
          <span className="absolute left-0 top-0.5 flex items-center justify-center w-6 h-6 rounded-full bg-orange-100 text-orange-600 text-[10px] font-black shadow-sm">
            {numberMatch[1]}
          </span>
          <HighlightText text={numberMatch[2]} keywords={content.motsCles} />
        </div>
      );
    }

    // Paragraphe classique
    return (
      <div key={idx} className="animate-fadeIn text-[15px] text-justify leading-relaxed mb-5 text-slate-700">
        <HighlightText text={para} keywords={content.motsCles} />
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-2 font-normal">
      {/* Titre affiné - Sans Gras (font-semibold) */}
      {content.titre && (
        <h4 className="text-lg font-semibold tracking-wide uppercase border-b-2 border-orange-100 pb-3 mb-6 inline-block" style={{ color: THEME_ORANGE_SAWA }}>
          {content.titre}
        </h4>
      )}

      {/* Rendu intelligent des paragraphes et listes */}
      <div className="flex flex-col">
        {content.paragraphes.map((para, idx) => renderParagraph(para, idx))}
      </div>

      {/* Invite d'exploration stylisée (Étape Suivante) */}
      {content.etapeSuivante && (
        <div className="mt-4 p-6 bg-slate-50 border border-dashed border-orange-200 rounded-2xl shadow-inner group">
