    if (!ai) return;

    if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new window.AudioContext({ sampleRate: 24000 });
    }
    const outputAudioContext = outputAudioContextRef.current;
    if (outputAudioContext.state === 'suspended') await outputAudioContext.resume();

    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
        const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
        const source = outputAudioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(outputAudioContext.destination);
        source.addEventListener('ended', () => currentPlayingSourcesRef.current.delete(source));
        source.start(nextStartTimeRef.current);
        nextStartTimeRef.current += audioBuffer.duration;
        currentPlayingSourcesRef.current.add(source);
      }
    } catch (error) { console.warn('TTS error:', error); }
  }, []);

  const handleSendMessage = useCallback(async (text: string, file?: File | null) => {
    const targetFile = file || selectedFile;
    if (!text.trim() && !targetFile) return;

    setIsAnalyzing(true);
    setErrorNotification(null);
    const userMsg: Message = { 
      id: `u-${Date.now()}`, 
      rawText: text || (targetFile ? `Audit document : ${targetFile.name}` : ''), 
      sender: 'user', 
      timestamp: new Date().toLocaleTimeString() 
    };
    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setSelectedFile(null);

    try {
      if (!chatSessionRef.current) throw new Error("Session non initialisée.");

      let result;
      if (targetFile) {
        const part = await fileToGenerativePart(targetFile);
        result = await chatSessionRef.current.sendMessage({ 
          message: { parts: [{ text: text || "Analyse documentaire pour l'audit." }, part] } 
