// Audio Decoding Utilities
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const cleanJson = (text: string) => {
  let cleaned = text.trim();
  if (cleaned.startsWith('```json')) {
    cleaned = cleaned.replace(/^```json/, '').replace(/```$/, '');
  } else if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```/, '').replace(/```$/, '');
  }
  return cleaned.trim();
};

const HighlightText = ({ text, keywords, isClosing = false }: { text: string, keywords: string[], isClosing?: boolean }) => {
  if (!text) return null;

  // Handle Markdown bold first
  const processMarkdownBold = (input: string) => {
    const parts = input.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={`bold-${i}`} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  if (!keywords || keywords.length === 0) return <>{processMarkdownBold(text)}</>;

  const escapedKeywords = keywords.map(kw => kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
  const regex = new RegExp(`(${escapedKeywords.join('|')})`, 'gi');
  const mainParts = text.split(regex);

  return (
    <>
      {mainParts.map((part, i) => {
        const isKeyword = keywords.some(kw => kw.toLowerCase() === part.toLowerCase());
        if (isKeyword) {
          return (
            <span key={i} className="font-bold" style={{ color: isClosing ? THEME_ORANGE_SAWA : THEME_BLUE_CUD }}>
              {part}
            </span>
          );
        }
        return <React.Fragment key={i}>{processMarkdownBold(part)}</React.Fragment>;
      })}
    </>
  );
};

const FormatResponse = ({ content }: { content: ResponseContent }) => {
  const renderParagraph = (para: string, idx: number) => {
    const trimmed = para.trim();
    // Match common list patterns: •, -, *, 1., 2)
    const bulletMatch = trimmed.match(/^([•\-\*])\s*(.*)/);
    const numberMatch = trimmed.match(/^(\d+)[\.\)]\s*(.*)/);

    if (bulletMatch) {
      return (
        <div key={idx} className="animate-fadeIn text-[15px] pl-7 relative leading-relaxed mb-4 text-slate-700 group/list">
          <span className="absolute left-1 top-0.5 text-orange-500 font-black text-xl leading-none transition-transform group-hover/list:scale-125">•</span>
          <div className="inline-block">
            <HighlightText text={bulletMatch[2]} keywords={content.motsCles} />
          </div>
        </div>
      );
    }

    if (numberMatch) {
      return (
        <div key={idx} className="animate-fadeIn text-[15px] pl-10 relative leading-relaxed mb-5 text-slate-700 group/list">
          <span className="absolute left-0 top-0.5 flex items-center justify-center w-7 h-7 rounded-full bg-orange-100 text-orange-600 text-[11px] font-black shadow-sm transition-all group-hover/list:bg-orange-500 group-hover/list:text-white">
            {numberMatch[1]}
          </span>
          <div className="inline-block align-middle">
            <HighlightText text={numberMatch[2]} keywords={content.motsCles} />
          </div>
        </div>
      );
    }

    // Default paragraph with better spacing and text alignment
    return (
      <div key={idx} className="animate-fadeIn text-[15px] text-justify leading-relaxed mb-6 text-slate-700">
        <HighlightText text={para} keywords={content.motsCles} />
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-2 font-normal">
      {content.titre && (
        <div className="mb-6">
          <h4 className="text-xl font-semibold tracking-tight uppercase border-l-4 border-orange-500 pl-4 py-1" style={{ color: THEME_ORANGE_SAWA }}>
            {content.titre}
          </h4>
        </div>
      )}

      <div className="flex flex-col">
        {content.paragraphes.map((para, idx) => renderParagraph(para, idx))}
      </div>

      {content.etapeSuivante && (
        <div className="mt-6 p-6 bg-slate-50 border-2 border-dashed border-orange-200 rounded-2xl shadow-inner hover:bg-orange-50/30 transition-colors">
          <div className="flex items-start gap-4">
             <div className="mt-1 flex-none w-6 h-6 bg-orange-500 rounded-full flex items-center justify-center text-white text-[11px] font-bold shadow-lg">→</div>
             <p className="text-sm font-medium italic text-slate-600 leading-relaxed">
               <HighlightText text={content.etapeSuivante} keywords={content.motsCles} isClosing={true} />
             </p>
          </div>
        </div>
      )}
    </div>
  );
};

