const THEME_ORANGE_SAWA = '#F97316'; // Orange Énergie

interface ResponseContent {
  titre: string;
  paragraphes: string[];
  motsCles: string[];
  etapeSuivante: string;
  suggestions?: string[];
}

interface Message {
  id: string;
