import { GoogleGenAI, Type } from "@google/genai";

export const config = {
  runtime: 'edge',
};

export default async function handler(req: Request) {
  if (req.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method not allowed' }), { status: 405 });
  }

  try {
    const { message, history, fileData } = await req.json();
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
      return new Response(JSON.stringify({ error: 'API Key not configured on server' }), { status: 500 });
    }

    const ai = new GoogleGenAI({ apiKey });

    // Configuration du modèle Gemini 3 Flash pour la rapidité et l'efficacité
    const model = 'gemini-3-flash-preview';

    const contents = [...history];

    // Si un fichier est présent (multimodal)
    if (fileData) {
      contents.push({
        role: 'user',
        parts: [
          { text: message || "Analyse ce document pour la CUD." },
          { inlineData: { data: fileData.data, mimeType: fileData.mimeType } }
        ]
      });
    } else {
      contents.push({
        role: 'user',
        parts: [{ text: message }]
      });
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            titre: { type: Type.STRING },
            paragraphes: { type: Type.ARRAY, items: { type: Type.STRING } },
            motsCles: { type: Type.ARRAY, items: { type: Type.STRING } },
            etapeSuivante: { type: Type.STRING },
            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["titre", "paragraphes", "motsCles", "etapeSuivante", "suggestions"]
        },
        systemInstruction: "Tu es Doulia, l'expert principal MED SAWA pour la CUD. Ton audience : Le Maire de Douala. Ton ton est institutionnel, technique et souverainiste. Tu maîtrises les dossiers d'urbanisme (permis de bâtir), de fiscalité (recettes municipales) et de pilotage urbain (nids-de-poule, salubrité). Réponds toujours en JSON structuré. Ne mets jamais de gras dans le titre.",
      },
    });

    return new Response(response.text, {
      headers: { 'Content-Type': 'application/json' },
    });

  } catch (error: any) {
    console.error("API Error:", error);
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}

