  title: string;
  description: string;
  roi: string;
  icon: React.ReactNode;
}

// Utilitaires Audio
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const fileToBase64 = (file: File): Promise<{ data: string; mimeType: string }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64Data = (reader.result as string).split(',')[1];
      resolve({ data: base64Data, mimeType: file.type });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const HighlightText = ({ text, keywords, isClosing = false }: { text: string, keywords: string[], isClosing?: boolean }) => {
  if (!text) return null;
  const processBold = (input: string) => {
    const parts = input.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => part.startsWith('**') ? <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong> : part);
  };
  if (!keywords?.length) return <>{processBold(text)}</>;
  const regex = new RegExp(`(${keywords.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|')})`, 'gi');
  return <>{text.split(regex).map((part, i) => keywords.some(k => k.toLowerCase() === part.toLowerCase()) ? <span key={i} className="font-bold" style={{ color: isClosing ? THEME_ORANGE_SAWA : THEME_BLUE_CUD }}>{part}</span> : processBold(part))}</>;
};

const FormatResponse = ({ content }: { content: ResponseContent }) => {
  return (
    <div className="flex flex-col gap-4">
      {content.titre && <h4 className="text-xl font-semibold tracking-tight uppercase border-l-4 border-orange-500 pl-4 py-1" style={{ color: THEME_ORANGE_SAWA }}>{content.titre}</h4>}
      <div className="space-y-4">
        {content.paragraphes.map((para, idx) => {
          const bullet = para.trim().match(/^([•\-\*]|\d+[\.\)])\s*(.*)/);
          return bullet ? (
            <div key={idx} className="pl-8 relative text-[15px] text-slate-700 leading-relaxed">
              <span className="absolute left-0 text-orange-500 font-black">{bullet[1].includes('.') ? bullet[1] : '•'}</span>
              <HighlightText text={bullet[2]} keywords={content.motsCles} />
            </div>
          ) : (
            <p key={idx} className="text-[15px] text-justify text-slate-700 leading-relaxed"><HighlightText text={para} keywords={content.motsCles} /></p>
          );
        })}
      </div>
      {content.etapeSuivante && (
        <div className="mt-4 p-5 bg-slate-50 border-2 border-dashed border-orange-200 rounded-2xl flex items-start gap-4 italic text-sm text-slate-600">
          <span className="bg-orange-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] font-bold">→</span>
          <HighlightText text={content.etapeSuivante} keywords={content.motsCles} isClosing />
        </div>
      )}
    </div>
  );
};

