import { GoogleGenAI, Type } from "@google/genai";

export const config = {
  runtime: 'edge',
};

export default async function handler(req: Request) {
  if (req.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Méthode non autorisée' }), { status: 405 });
  }

  try {
    const { prompt, history } = await req.json();
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
      return new Response(JSON.stringify({ error: 'La clé API n’est pas configurée sur le serveur Vercel' }), { status: 500 });
    }

    const ai = new GoogleGenAI({ apiKey });

    // Nous utilisons Gemini 3 Flash pour la rapidité d'exécution sur le terrain (Akwa, Bonabéri)
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            titre: { type: Type.STRING },
            paragraphes: { type: Type.ARRAY, items: { type: Type.STRING } },
            motsCles: { type: Type.ARRAY, items: { type: Type.STRING } },
            etapeSuivante: { type: Type.STRING },
            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["titre", "paragraphes", "motsCles", "etapeSuivante", "suggestions"]
        },
        systemInstruction: "Tu es Doulia, l'Expert Principal de MED SAWA. Tu conseilles le Maire de Douala. Ton ton est technique, bilingue et tourné vers l'efficacité. Tu parles de fiscalité (Akwa), d'urbanisme (Bonanjo) et de Smart City. Réponds toujours en JSON. Ne mets jamais de gras dans le titre.",
      },
    });

    return new Response(response.text, {
      headers: { 'Content-Type': 'application/json' },
    });

  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";

const THEME_BLUE_CUD = '#1E3A8A';
const THEME_ORANGE_SAWA = '#F97316';

interface ResponseContent {
  titre: string;
  paragraphes: string[];
  motsCles: string[];
  etapeSuivante: string;
  suggestions?: string[];
}

interface Message {
  id: string;
  structuredContent?: ResponseContent;
  rawText?: string;
  sender: 'user' | 'ai' | 'system';
  timestamp: string;
  suggestions?: string[]; 
  isError?: boolean;
}

// Utilitaires Audio pour la synthèse vocale (lecture intégrale)
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

