  const historyRef = useRef<any[]>([]);

  const stopAudio = useCallback(() => {
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    setIsSpeaking(false);
  }, []);

  const playAudio = useCallback(async (text: string) => {
    // Note: Pour le TTS, on utilise une clé temporaire ou on proxy aussi. 
    // Ici, nous utilisons l'API cliente car le TTS est moins sensible, 
    // mais idéalement Vercel gère l'injection de la clé au build.
    const apiKey = (process.env as any).API_KEY; 
    if (!apiKey) return;

    const ai = new GoogleGenAI({ apiKey });
    stopAudio();
    if (!audioCtxRef.current) audioCtxRef.current = new AudioContext({ sampleRate: 24000 });
    const ctx = audioCtxRef.current;
    if (ctx.state === 'suspended') await ctx.resume();

    try {
      setIsSpeaking(true);
      const res = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } } },
      });
      const b64 = res.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (b64) {
        const buffer = await decodeAudioData(decode(b64), ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.onended = () => { sourcesRef.current.delete(source); if (!sourcesRef.current.size) setIsSpeaking(false); };
        source.start(0);
        sourcesRef.current.add(source);
      } else setIsSpeaking(false);
    } catch (e) { setIsSpeaking(false); }
  }, [stopAudio]);

  const send = useCallback(async (text: string) => {
    if (!text.trim()) return;
    setIsAnalyzing(true);
    const userMsg: Message = { id: `u-${Date.now()}`, rawText: text, sender: 'user', timestamp: new Date().toLocaleTimeString() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');

    try {
      // APPEL SÉCURISÉ : On appelle notre propre route API, pas Google directement.
      const response = await fetch('/api/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ prompt: text, history: historyRef.current })
      });

      if (!response.ok) throw new Error("Erreur de communication avec le serveur CUD.");

      const data: ResponseContent = await response.json();

      // Mise à jour historique
      historyRef.current.push({ role: 'user', parts: [{ text }] });
      historyRef.current.push({ role: 'model', parts: [{ text: JSON.stringify(data) }] });

      setMessages(prev => [...prev, { id: `ai-${Date.now()}`, structuredContent: data, sender: 'ai', timestamp: new Date().toLocaleTimeString(), suggestions: data.suggestions }]);
      playAudio(`${data.titre}. ${data.paragraphes.join('. ')}. ${data.etapeSuivante}`);

    } catch (e: any) {
      setMessages(prev => [...prev, { id: `e-${Date.now()}`, rawText: "Doulia indisponible. Vérifiez votre clé API sur Vercel.", sender: 'system', timestamp: new Date().toLocaleTimeString(), isError: true }]);
    } finally { setIsAnalyzing(false); }
  }, [playAudio]);

  useEffect(() => { if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight; }, [messages]);

  return (
    <div className="h-screen flex flex-col bg-white text-slate-800 overflow-hidden font-sans">
      <div className="fixed inset-0 bg-[radial-gradient(circle_at_top_right,_#f8fafc,_#ffffff)] -z-10"></div>

      <header className="px-6 py-4 bg-white/90 backdrop-blur-md border-b border-slate-100 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-3">
          <img src="https://douala.cm/assets/images/logo_cud.png" alt="CUD" className="h-10 w-auto" />
          <div className="flex flex-col">
            <h1 className="text-[10px] font-black text-blue-900 tracking-tighter uppercase">DOULIA - SÉCURITÉ CUD</h1>
            <span className="text-[8px] font-bold text-orange-500 uppercase">Expertise MED SAWA (Backend Protected)</span>
          </div>
        </div>
        {isSpeaking && (
          <div className="flex items-center gap-1.5 px-3 py-1 bg-orange-50 rounded-full animate-pulse border border-orange-100">
            <div className="flex gap-0.5">
               <span className="w-1 h-3 bg-orange-500 rounded-full"></span>
               <span className="w-1 h-3 bg-orange-500 rounded-full"></span>
               <span className="w-1 h-3 bg-orange-500 rounded-full"></span>
            </div>
            <span className="text-[8px] font-black text-orange-600 uppercase">Doulia vous parle</span>
          </div>
        )}
      </header>

      <main className="flex-1 flex flex-col p-4 gap-4 overflow-hidden relative">
        <div ref={chatRef} className="flex-1 overflow-y-auto p-4 space-y-8 custom-scrollbar">
          {messages.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-8 animate-fadeIn">
               <div className="w-20 h-20 bg-blue-900 rounded-3xl flex items-center justify-center text-white mb-6 shadow-2xl">
                 <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
               </div>
               <h2 className="text-xl font-black text-blue-950 uppercase mb-2">Bienvenue Monsieur le Maire</h2>
               <p className="text-sm text-slate-500 max-w-md font-medium">Posez votre question sur la fiscalité d'Akwa ou l'urbanisme de Bonanjo. Votre session est entièrement sécurisée par MED SAWA.</p>
            </div>
          )}

          {messages.map((m) => (
            <div key={m.id} className={`flex flex-col ${m.sender === 'user' ? 'items-end' : 'items-start'} animate-fadeIn`}>
              <div className={`max-w-[90%] p-6 rounded-2xl shadow-sm ${
                m.sender === 'user' ? 'bg-blue-900 text-white rounded-br-none' : 'bg-white border border-slate-100 text-slate-800 rounded-bl-none'
              }`}>
                {m.structuredContent ? (
                  <div className="space-y-4">
                    <h4 className="text-lg font-bold uppercase" style={{ color: THEME_ORANGE_SAWA }}>{m.structuredContent.titre}</h4>
                    {m.structuredContent.paragraphes.map((p, i) => <p key={i} className="text-sm leading-relaxed text-justify">{p}</p>)}
                    <div className="p-4 bg-slate-50 border-l-4 border-orange-500 text-xs italic font-medium">{m.structuredContent.etapeSuivante}</div>
                  </div>
                ) : <p className="text-sm font-medium">{m.rawText}</p>}
              </div>
              <span className="text-[8px] font-black uppercase text-slate-400 mt-2 px-2">{m.sender === 'user' ? 'CUD Cabinet' : 'DOULIA AI'}</span>
            </div>
          ))}
          {isAnalyzing && <div className="text-[10px] font-black text-orange-500 uppercase animate-pulse">Doulia consulte les registres fiscaux...</div>}
        </div>

        <div className="p-4 bg-white border-t border-slate-50">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyDown={(e) => e.key === 'Enter' && send(input)}
              placeholder="QUELLE EST VOTRE DIRECTIVE, MONSIEUR LE MAIRE ?" 
              className="flex-1 h-14 px-6 border-2 border-slate-100 rounded-2xl focus:border-orange-500 outline-none text-sm font-medium"
            />
            <button 
              onClick={() => send(input)} 
              disabled={isAnalyzing}
              className="h-14 px-8 bg-blue-900 text-white rounded-2xl font-black text-[11px] uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg active:scale-95 disabled:bg-slate-300"
            >
              {isAnalyzing ? '...' : 'ANALYSÉ'}
            </button>
          </div>
        </div>
      </main>

      <footer className="px-8 py-3 bg-white border-t border-slate-50 flex items-center justify-between text-[8px] font-black text-slate-400 uppercase tracking-widest">
        <div className="flex gap-4"><span>PROTECTION SOUVERAINE : MED SAWA</span><span className="text-orange-500">BACKEND SECURED</span></div>
        <span>Douala Smart City © 2026</span>
      </footer>
    </div>
  );
};

export default App;
